using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Source-gen context that only knows about Person
var options = MyContext.Default.Options;

// 1️⃣  Strongly-typed retrieval: GetTypeInfo<T>() → JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Typed info  : {personInfo.Type.Name}  (is JsonTypeInfo<Person>: {personInfo is JsonTypeInfo<Person>})");

var sample = new Person("Ada", 36);
string json = JsonSerializer.Serialize(sample, personInfo);
Console.WriteLine($"Serialized  : {json}");

// 2️⃣  Probe without throwing: TryGetTypeInfo()
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"Probe Person: found ({found!.Type.Name})");
else
    Console.WriteLine("Probe Person: not found");

// This type is *not* in the source-gen context, so TryGetTypeInfo returns false
// instead of throwing InvalidOperationException.
if (options.TryGetTypeInfo(typeof(Order), out _))
    Console.WriteLine("Probe Order : found");
else
    Console.WriteLine("Probe Order : not found (no metadata registered)");

// Records used in the demo
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// Source-generated context — only Person is registered
[JsonSourceGenerationOptions(WriteIndented = false)]
